func validateHeaders(r *http.Request, serviceHeaders, methodHeaders []*onekithttp.Header) *onekithttp.ValidationError {
	// Merge service and method headers, with method headers taking precedence
	allHeaders := make(map[string]*onekithttp.Header)

	// Add service headers first
	for _, header := range serviceHeaders {
		if header.GetRequired() {
			allHeaders[strings.ToLower(header.GetName())] = header
		}
	}

	// Add method headers (override service headers if same name)
	for _, header := range methodHeaders {
		if header.GetRequired() {
			allHeaders[strings.ToLower(header.GetName())] = header
		}
	}

	// Collect all validation violations
	var violations []*onekithttp.FieldViolation

	// Validate each required header
	for _, headerSpec := range allHeaders {
		value := r.Header.Get(headerSpec.GetName())
		if value == "" {
			violations = append(violations, &onekithttp.FieldViolation{
				Field:       headerSpec.GetName(),
				Description: fmt.Sprintf("required header '%s' is missing", headerSpec.GetName()),
			})
			continue
		}

		if err := validateHeaderValue(headerSpec, value); err != nil {
			violations = append(violations, &onekithttp.FieldViolation{
				Field:       headerSpec.GetName(),
				Description: fmt.Sprintf("header '%s' validation failed: %v", headerSpec.GetName(), err),
			})
		}
	}

	// Return ValidationError if there are violations
	if len(violations) > 0 {
		return &onekithttp.ValidationError{
			Violations: violations,
		}
	}

	return nil
}

// validateHeaderValue validates a single header value against its specification
func validateHeaderValue(headerSpec *onekithttp.Header, value string) error {
	headerType := headerSpec.GetType()
	format := headerSpec.GetFormat()

	// Validate based on type
	switch headerType {
	case "string":
		return validateStringHeader(value, format)
	case "integer":
		return validateIntegerHeader(value)
	case "number":
		return validateNumberHeader(value)
	case "boolean":
		return validateBooleanHeader(value)
	case "array":
		return validateArrayHeader(value)
	default:
		// Default to string validation if type is not specified
		return validateStringHeader(value, format)
	}
}

// validateStringHeader validates string headers with optional format validation
func validateStringHeader(value, format string) error {
	if !utf8.ValidString(value) {
		return fmt.Errorf("value is not valid UTF-8")
	}

	// Apply format-specific validation
	switch format {
	case "uuid":
		return validateUUIDFormat(value)
	case "email":
		return validateEmailFormat(value)
	case "date-time":
		return validateDateTimeFormat(value)
	case "date":
		return validateDateFormat(value)
	case "time":
		return validateTimeFormat(value)
	}

	return nil
}

// validateIntegerHeader validates integer headers
func validateIntegerHeader(value string) error {
	_, err := strconv.ParseInt(value, 10, 64)
	if err != nil {
		return fmt.Errorf("value is not a valid integer: %w", err)
	}
	return nil
}

// validateNumberHeader validates numeric headers (float)
func validateNumberHeader(value string) error {
	_, err := strconv.ParseFloat(value, 64)
	if err != nil {
		return fmt.Errorf("value is not a valid number: %w", err)
	}
	return nil
}

// validateBooleanHeader validates boolean headers
func validateBooleanHeader(value string) error {
	_, err := strconv.ParseBool(value)
	if err != nil {
		return fmt.Errorf("value is not a valid boolean: %w", err)
	}
	return nil
}

// validateArrayHeader validates array headers (comma-separated values)
func validateArrayHeader(value string) error {
	// Arrays are typically comma-separated values
	// Basic validation: ensure it's not empty
	if strings.TrimSpace(value) == "" {
		return fmt.Errorf("array value cannot be empty")
	}
	return nil
}

// validateUUIDFormat validates UUID format (basic check)
func validateUUIDFormat(value string) error {
	// Basic UUID format check: 8-4-4-4-12 hex digits
	if len(value) != 36 {
		return fmt.Errorf("UUID must be 36 characters long")
	}

	// Check for correct dash positions
	if value[8] != '-' || value[13] != '-' || value[18] != '-' || value[23] != '-' {
		return fmt.Errorf("invalid UUID format")
	}

	return nil
}

// validateEmailFormat validates email format (basic check)
func validateEmailFormat(value string) error {
	// Basic email format check
	if !strings.Contains(value, "@") {
		return fmt.Errorf("invalid email format: missing @")
	}

	parts := strings.Split(value, "@")
	if len(parts) != 2 || parts[0] == "" || parts[1] == "" {
		return fmt.Errorf("invalid email format")
	}

	return nil
}

// validateDateTimeFormat validates RFC3339 date-time format
func validateDateTimeFormat(value string) error {
	_, err := time.Parse(time.RFC3339, value)
	if err != nil {
		return fmt.Errorf("invalid date-time format, expected RFC3339: %w", err)
	}
	return nil
}

// validateDateFormat validates date format (YYYY-MM-DD)
func validateDateFormat(value string) error {
	_, err := time.Parse("2006-01-02", value)
	if err != nil {
		return fmt.Errorf("invalid date format, expected YYYY-MM-DD: %w", err)
	}
	return nil
}

// validateTimeFormat validates time format (HH:MM:SS)
func validateTimeFormat(value string) error {
	_, err := time.Parse("15:04:05", value)
	if err != nil {
		return fmt.Errorf("invalid time format, expected HH:MM:SS: %w", err)
	}
	return nil
}
